import React from "react";
import { useUploader } from "../MainUploader";
import { Button, Flex, Text } from "../../../_compat";
import { Icon } from "../../../primitives";
import { useLanguage } from "../../../_compat";

const MultipleFileUploader = () => {
    const { onPick, files, removeFile, disabled, limit, placeholder, isClassicUploader } =
        useUploader();
    const { t } = useLanguage();

    if (!isClassicUploader) {
        // Non-classic: dashed container with upload icon + localized phrase
        return (
            <Flex w={"full"} flexDirection={"column"} gap={8} opacity={disabled ? 0.5 : 1}>
                <Flex
                    w={"full"}
                    borderW={2}
                    borderStyle={"dashed"}
                    borderColor={"primary"}
                    borderRadiusLeft={"lg"}
                    borderRadiusRight={"lg"}
                    alignItems={"center"}
                    justifyContent={"center"}
                    flexDirection={"column"}
                    py={32}
                    px={16}
                    gap={8}
                    onClick={onPick as any}
                >
                    <Icon name="cloud-upload" size={'lg'} color={"primary"} />
                    <Text fontSize={14} color={"text-secondary"} textAlign={"center"}>
                        {t("tapToUpload")}
                    </Text>
                </Flex>
                {files.length > 0 && (
                    <Text fontSize={13} color={"text-secondary"} textAlign={"center"}>
                        {t("filesSelected", files.length)} / {limit}
                    </Text>
                )}
            </Flex>
        );
    }

    return (
        <Flex w={"full"} flexDirection={"column"} gap={8}>
            {files.map((f, idx) => (
                <Flex
                    key={`${f.name}-${idx}`}
                    flexDirection={"row"}
                    justifyContent={"space-between"}
                    alignItems={"center"}
                    gap={8}
                >
                    <Text
                        as={"span"}
                        fontSize={13}
                        color={"text-secondary"}
                        textOverflow={"ellipsis"}
                        whiteSpace={"nowrap"}
                        flex={1}
                    >
                        {f.shortName}
                    </Text>
                    <Button
                        icon="pi pi-times"
                        size={"sm"}
                        severity={"danger"}
                        onClick={removeFile(idx)}
                        disabled={disabled}
                    />
                </Flex>
            ))}

            <Button
                label={placeholder ?? t("chooseFile")}
                severity={"secondary"}
                outlined
                w={"full"}
                onClick={onPick as any}
                disabled={disabled || files.length >= limit}
            />
        </Flex>
    );
};

export default MultipleFileUploader;
